d_q5 = {"a": 2, "b": 4, "c": 5, "d": 6, "e": 7, "f": 9, "g": 11, "h": 12}

def is_prime(n):
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

for k, v in d_q5.items():
    print(f"{k}: {v}, prime: {is_prime(v)}")

n5 = sum(1 for v in d_q5.values() if is_prime(v))
print(f"\nN5 = {n5}")
